:where(*, *::before, *::after) {
  box-sizing: border-box;
  border-color: var(--border);
  outline-color: color-mix(in oklch, var(--ring) 50%, transparent);
}

html {
  font-family: var(--font-sans), ui-sans-serif, system-ui, sans-serif;
  -webkit-text-size-adjust: 100%;
  tab-size: 4;
  line-height: 1.5;
}

body {
  margin: 0;
  min-height: 100dvh;
  background-color: var(--background);
  color: var(--foreground);
}

:where(img, svg, video) {
  display: block;
  max-width: 100%;
}

:where(canvas) {
  display: block;
}

:where(button, input, optgroup, select, textarea) {
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  font-weight: inherit;
  letter-spacing: inherit;
  color: inherit;
  margin: 0;
}

:where(button) {
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
}

:where(a) {
  color: inherit;
  text-decoration: inherit;
}

:where(h1, h2, h3, h4, h5, h6, p) {
  margin: 0;
}

:where(ul, ol) {
  margin: 0;
  padding: 0;
  list-style: none;
}

:where(table) {
  border-collapse: collapse;
}

:where(:focus-visible) {
  outline: none;
}

@keyframes df-spin {
  to {
    transform: rotate(360deg);
  }
}

@keyframes df-progress-indeterminate {
  0% {
    transform: translateX(-100%);
  }
  100% {
    transform: translateX(var(--df-progress-indeterminate-travel));
  }
}

@keyframes df-pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes df-enter {
  from {
    opacity: var(--df-enter-opacity, 1);
    transform: translate3d(
        var(--df-enter-translate-x, 0),
        var(--df-enter-translate-y, 0),
        0
      )
      scale(var(--df-enter-scale, 1));
  }
}

@keyframes df-exit {
  to {
    opacity: var(--df-exit-opacity, 1);
    transform: translate3d(
        var(--df-exit-translate-x, 0),
        var(--df-exit-translate-y, 0),
        0
      )
      scale(var(--df-exit-scale, 1));
  }
}

@keyframes home-reveal {
  from {
    opacity: 0;
    transform: translateY(var(--df-motion-travel-xl));
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

@keyframes home-shader-drift {
  0% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
  50% {
    background-position: 80% 20%, 20% 80%, 40% 60%;
  }
  100% {
    background-position: 0% 40%, 100% 60%, 50% 50%;
  }
}

@keyframes home-mesh-float {
  0%,
  100% {
    transform: translate3d(0, 0, 0) scale(1);
  }
  50% {
    transform: translate3d(4%, -3%, 0) scale(1.04);
  }
}

@keyframes home-stage-float {
  0%,
  100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(calc(-1 * var(--df-motion-travel-sm)));
  }
}

@keyframes df-marquee {
  from {
    transform: translateX(0);
  }
  to {
    transform: translateX(calc(-100% - var(--df-marquee-gap)));
  }
}

@keyframes df-tab-progress {
  from {
    transform: scaleX(0);
  }
  to {
    transform: scaleX(1);
  }
}

@keyframes df-spectrum-text {
  0% {
    background-position: 0% 50%;
  }
  25% {
    background-position: 50% 100%;
  }
  50% {
    background-position: 100% 50%;
  }
  75% {
    background-position: 50% 0%;
  }
  100% {
    background-position: 0% 50%;
  }
}

.home-reveal {
  animation: home-reveal var(--df-duration-reveal) var(--df-ease-decelerate) both;
}

.df-reveal {
  opacity: 0;
  transform: translateY(var(--df-reveal-y, var(--df-motion-travel-3xl)));
  transition:
    opacity var(--df-duration-reveal-long) var(--df-ease-decelerate),
    transform var(--df-duration-reveal-long) var(--df-ease-decelerate),
    color var(--df-duration-reveal-long) var(--df-ease-decelerate);
  transition-delay: var(--df-reveal-delay, 0ms);
  will-change: opacity, transform;
}

.df-reveal.is-inview {
  opacity: 1;
  transform: translateY(0);
}

.df-reveal-y-48 {
  --df-reveal-y: var(--df-motion-travel-4xl);
}

.df-reveal-y-72 {
  --df-reveal-y: var(--df-motion-travel-5xl);
}

.df-reveal-emphasis {
  color: color-mix(in oklch, var(--foreground) 25%, transparent);
  opacity: 1;
  transform: none;
}

.df-reveal-emphasis.is-inview {
  color: var(--foreground);
}

.home-grid-fade {
  background-image:
    linear-gradient(
      to right,
      var(--home-grid-line) var(--border-width-hairline),
      transparent var(--border-width-hairline)
    ),
    linear-gradient(
      to bottom,
      var(--home-grid-line) var(--border-width-hairline),
      transparent var(--border-width-hairline)
    );
  background-size: var(--home-grid-size);
  mask-image: linear-gradient(180deg, black 0%, transparent 88%);
}

.home-section-tools {
  background: var(--home-section-tools-wash);
}

.home-preview-frame {
  box-shadow: var(--home-preview-frame-shadow);
}

.home-preview-shader {
  background-image: var(--home-preview-shader-image);
  background-size: 140% 140%, 140% 140%, 140% 140%, 100% 100%;
  animation: home-shader-drift var(--home-shader-drift-duration) ease-in-out
    infinite;
}

.home-preview-mesh {
  background: var(--home-preview-mesh-bg);
}

.home-preview-mesh::before,
.home-preview-mesh::after {
  content: "";
  position: absolute;
  inset: -20%;
  border-radius: var(--radius-full);
  filter: blur(var(--df-blur-mesh));
  animation: home-mesh-float var(--home-mesh-float-duration) ease-in-out infinite;
}

.home-preview-mesh::before {
  background: var(--home-preview-mesh-blob-a);
  left: -10%;
  top: -15%;
}

.home-preview-mesh::after {
  background: var(--home-preview-mesh-blob-b);
  right: -15%;
  bottom: -20%;
  animation-delay: -3s;
}

.home-hero-stage {
  box-shadow: var(--home-hero-stage-shadow);
}

.home-hero-collage-gap {
  margin-top: var(--home-hero-collage-gap);
}

@media (min-width: 640px) {
  :root {
    --home-hero-collage-gap: calc(32 * var(--spacing-unit, 0.25rem));
  }
}

@media (min-width: 1024px) {
  :root {
    --home-hero-collage-gap: calc(36 * var(--spacing-unit, 0.25rem));
  }
}

.home-hero-collage-stage {
  --home-hero-collage-stage-ring: color-mix(
    in oklch,
    var(--border) 70%,
    transparent
  );
  background: var(--muted);
  box-shadow:
    0 0 0 var(--border-width-hairline) var(--home-hero-collage-stage-ring),
    var(--home-hero-collage-stage-elevation);
}

.home-hero-card {
  background: var(--card);
  box-shadow: var(--home-hero-card-shadow);
  will-change: transform, opacity;
  backface-visibility: hidden;
}

.home-hero-card__float {
  will-change: transform;
  backface-visibility: hidden;
}

.home-hero-card-label {
  background: color-mix(in oklch, var(--background) 72%, transparent);
  box-shadow: var(--home-hero-card-label-shadow);
}

.home-stage-frame {
  animation: home-stage-float var(--home-stage-float-duration) ease-in-out
    infinite;
}

.home-stage-frame:nth-child(2) {
  animation-delay: -2.5s;
}

.home-stage-frame:nth-child(3) {
  animation-delay: -4.5s;
}

.df-marquee {
  --df-marquee-gap: calc(3 * var(--spacing-unit, 0.25rem));
  overflow: hidden;
  mask-image: linear-gradient(
    90deg,
    transparent,
    black 8%,
    black 92%,
    transparent
  );
}

.df-marquee-track {
  display: flex;
  gap: var(--df-marquee-gap);
}

.df-marquee-group {
  display: flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: space-around;
  gap: var(--df-marquee-gap);
  min-width: 100%;
  animation: df-marquee var(--df-marquee-duration, 30s) linear infinite;
}

.df-marquee:hover .df-marquee-group {
  animation-play-state: paused;
}

.df-tab-progress {
  transform: scaleX(0);
  transform-origin: left center;
}

.df-tab-progress.is-active {
  animation: df-tab-progress var(--df-tab-duration, 6s) linear forwards;
}

.df-accordion-panel {
  display: grid;
  grid-template-rows: 0fr;
  transition: grid-template-rows var(--df-duration-panel) var(--df-ease-decelerate);
}

.df-accordion-panel[data-open="true"] {
  grid-template-rows: 1fr;
}

.df-accordion-panel > div {
  overflow: hidden;
}

.df-accordion-chevron {
  transition: transform var(--df-duration-panel) var(--df-ease-decelerate);
}

.df-accordion-chevron[data-open="true"] {
  transform: rotate(180deg);
}

.df-auto-tab-panel {
  opacity: 0;
  transform: translateY(var(--df-motion-travel-lg));
  transition:
    opacity var(--df-duration-panel-soft) var(--df-ease-decelerate),
    transform var(--df-duration-panel-soft) var(--df-ease-decelerate);
  pointer-events: none;
}

.df-auto-tab-panel.is-active {
  opacity: 1;
  transform: translateY(0);
  pointer-events: auto;
}

@media (prefers-reduced-motion: reduce) {
  .home-reveal,
  .home-preview-shader,
  .home-preview-mesh::before,
  .home-preview-mesh::after,
  .home-stage-frame,
  .df-marquee-group,
  .df-tab-progress.is-active,
  .df-spectrum-text-fill,
  .animate-spin,
  .animate-pulse,
  :where([data-df="spinner"] svg),
  .df-spinner svg,
  :where([data-df="progress"][data-state="indeterminate"] .df-progress-indicator),
  .df-progress[data-state="indeterminate"] .df-progress-indicator {
    animation: none !important;
  }

  .df-reveal,
  .df-reveal-emphasis,
  .df-auto-tab-panel,
  .df-accordion-panel,
  .df-accordion-chevron {
    transition: none !important;
  }

  .df-reveal {
    opacity: 1;
    transform: none;
  }

  .df-reveal-emphasis {
    color: var(--foreground);
  }

  .df-auto-tab-panel {
    opacity: 0;
    transform: none;
  }

  .df-auto-tab-panel.is-active {
    opacity: 1;
  }

  .df-tab-progress {
    transform: scaleX(1);
  }
}

:where([data-corner-shape="round"]) {
  --df-corner-shape: var(--df-corner-shape-round);
}

:where([data-corner-shape="smooth"]) {
  --df-corner-shape: var(--df-corner-shape-smooth);
}

.corner-round {
  --df-corner-shape: var(--df-corner-shape-round);
}

.corner-smooth {
  --df-corner-shape: var(--df-corner-shape-smooth);
}

/* Cap-height label centering for leading-none flex chrome. */
:where(
  [data-df="badge"],
  [data-df="choice-chip"],
  [data-df="content-switcher-item"],
  [data-df="tabs-trigger"],
  [data-df="floating-controls-item"],
  [data-df="overlay-hint"],
  [data-df="button"] > [data-slot="badge"]
),
.df-content-switcher-item,
.df-tabs-trigger,
.df-floating-controls-item,
.df-overlay-hint,
.df-btn > [data-slot="badge"] {
  --df-label-line-height: var(--df-leading-none);
  line-height: var(--df-label-line-height);
}

@supports (height: 1cap) and (not (text-box-trim: trim-both)) {
  :where(
    [data-df="badge"],
    [data-df="choice-chip"],
    [data-df="content-switcher-item"],
    [data-df="tabs-trigger"],
    [data-df="floating-controls-item"],
    [data-df="overlay-hint"],
    [data-df="button"] > [data-slot="badge"]
  ),
  .df-content-switcher-item,
  .df-tabs-trigger,
  .df-floating-controls-item,
  .df-overlay-hint,
  .df-btn > [data-slot="badge"] {
    --df-label-line-height: 1cap;
  }
}

@supports (text-box-trim: trim-both) {
  :where(
    [data-df="badge"],
    [data-df="choice-chip"],
    [data-df="content-switcher-item"],
    [data-df="tabs-trigger"],
    [data-df="floating-controls-item"],
    [data-df="overlay-hint"],
    [data-df="button"] > [data-slot="badge"]
  ),
  .df-content-switcher-item,
  .df-tabs-trigger,
  .df-floating-controls-item,
  .df-overlay-hint,
  .df-btn > [data-slot="badge"] {
    text-box: trim-both cap alphabetic;
  }
}

/* Interactive chrome is not document text. Fields and panel bodies stay selectable. */
:where(
  [data-df="button"],
  [data-df="badge"],
  [data-df="choice-chip"],
  [data-df="content-switcher-item"],
  [data-df="tabs-trigger"],
  [data-df="floating-controls-item"],
  [data-df="overlay-hint"],
  [data-df="toggle-group-item"],
  [data-df="accordion-trigger"],
  [data-df="select-trigger"],
  [data-df="select-field-help-button"],
  [data-df="select-value-badge"],
  [data-df="select-value-badge-remove"],
  [data-df="option-list-trigger"],
  [data-df="option-list-item"],
  [data-df="option-list-scroll-up-button"],
  [data-df="option-list-scroll-down-button"],
  [data-df="popover-trigger"],
  [data-df="tooltip-trigger"],
  [data-df="switch"],
  [data-df="color-picker-trigger"],
  [data-df="label"],
  [data-df="input-prefix"],
  [data-df="input-suffix"],
  [data-df="input-label"],
  [data-df="input-clear"],
  [data-df="input-icon"],
  [data-df="search-input-clear"],
  [data-df="search-input-icon"],
  [data-df="slider"],
  [data-df="slider-control"],
  [data-df="tick-slider"],
  [data-df="image-dropzone"],
  [data-df="progress"],
  [data-df="scroll-area-scrollbar"],
  [data-df="dock-panel-header"],
  [data-df="dock-panel-title"],
  [data-df="dock-panel-subtitle"],
  [data-df="dock-panel-expand-trigger"],
  [data-df="dock-panel-expand-chip"],
  [data-df="dock-panel-expand-label"],
  [data-df="dock-panel-rail"],
  [data-df="nav-rail-item"],
  [data-df="options-panel-header"],
  [data-df="options-panel-title"],
  [data-df="options-panel-trigger"]
),
.df-btn,
.df-content-switcher-item,
.df-tabs-trigger,
.df-floating-controls-item,
.df-overlay-hint,
.df-toggle-item,
.df-toast-close {
  user-select: none;
}

@supports (corner-shape: squircle) {
  :where([data-df]),
  :where([data-df])::before,
  :where([data-df])::after,
  :where([data-df] *),
  :where([data-df] *)::before,
  :where([data-df] *)::after,
  :where(.df-btn),
  :where(.df-input),
  :where(.df-toast),
  :where(.df-toggle-item),
  :where(.df-overlay-hint),
  :where(.corner-round),
  :where(.corner-smooth),
  :where([class*="rounded-"]) {
    corner-shape: var(--df-corner-shape);
  }
}

:where([data-df="button"]) {
  position: relative;
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  gap: calc(1.5 * var(--spacing-unit, 0.25rem));
  border-radius: var(--radius-4xl);
  border: var(--border-width-hairline) solid transparent;
  background-clip: padding-box;
  font-size: var(--df-text-sm);
  line-height: var(--df-leading-5);
  font-weight: var(--df-font-weight-medium);
  white-space: nowrap;
  transition: color var(--df-duration-base), border-color var(--df-duration-base),
    box-shadow var(--df-duration-base), transform var(--df-duration-base);
  outline: none;
  cursor: pointer;
}

:where([data-df="button"][data-badge]) {
  overflow: visible;
}

:where([data-df="button"] > [data-slot="badge"]),
.df-btn > [data-slot="badge"] {
  position: absolute;
  top: 0;
  inset-inline-end: 0;
  inset-inline-start: auto;
  z-index: var(--z-raised);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: var(--df-button-badge-size);
  height: var(--df-button-badge-size);
  padding-inline: var(--df-button-badge-pad-inline);
  pointer-events: none;
  translate: 50% -50%;
  font-variant-numeric: tabular-nums;
  font-weight: var(--df-font-weight-semibold);
}

:where([data-df="button"][data-badge-position="inset"] > [data-slot="badge"]),
.df-btn[data-badge-position="inset"] > [data-slot="badge"] {
  top: var(--df-button-badge-inset);
  inset-inline-end: var(--df-button-badge-inset);
}

:where([data-df="button"][data-badge-side="start"] > [data-slot="badge"]),
.df-btn[data-badge-side="start"] > [data-slot="badge"] {
  inset-inline-end: auto;
  inset-inline-start: 0;
  translate: -50% -50%;
}

:where([data-df="button"][data-badge-side="start"][data-badge-position="inset"] > [data-slot="badge"]),
.df-btn[data-badge-side="start"][data-badge-position="inset"] > [data-slot="badge"] {
  inset-inline-end: auto;
  inset-inline-start: var(--df-button-badge-inset);
}

:where(:dir(rtl) [data-df="button"][data-badge-side="end"] > [data-slot="badge"]),
:where(:dir(rtl) .df-btn[data-badge-side="end"] > [data-slot="badge"]),
:where(:dir(rtl) [data-df="button"]:not([data-badge-side]) > [data-slot="badge"]),
:where(:dir(rtl) .df-btn:not([data-badge-side]) > [data-slot="badge"]) {
  translate: -50% -50%;
}

:where(:dir(rtl) [data-df="button"][data-badge-side="start"] > [data-slot="badge"]),
:where(:dir(rtl) .df-btn[data-badge-side="start"] > [data-slot="badge"]) {
  translate: 50% -50%;
}

:where([data-df="button"]:focus-visible) {
  border-color: var(--ring);
  box-shadow: var(--focus-ring);
}

:where([data-df="button"]:active:not([aria-haspopup])) {
  transform: translateY(var(--df-press-offset));
}
:where(
    [data-df="button"][data-variant="plain"][data-size^="icon"]:active:not(
        [aria-haspopup]
      )
  ) {
  transform: none;
}

:where([data-df="button"]:disabled),
:where([data-df="button"][aria-disabled="true"]) {
  pointer-events: none;
  opacity: var(--opacity-disabled);
}

:where([data-df="button"][data-loading][data-loading-appearance="solid"]:disabled),
:where([data-df="button"][data-loading][data-loading-appearance="solid"][aria-disabled="true"]),
.df-btn[data-loading][data-loading-appearance="solid"]:disabled,
.df-btn[data-loading][data-loading-appearance="solid"][aria-disabled="true"] {
  opacity: 1;
}

:where([data-df="button"][data-loading][data-loading-appearance="solid"] > [data-slot="label"]),
:where([data-df="button"][data-loading][data-loading-appearance="solid"] > [data-slot="leading"]:not(:has([data-df="spinner"]))),
:where([data-df="button"][data-loading][data-loading-appearance="solid"] > [data-slot="trailing"]:not(:has([data-df="spinner"]))),
.df-btn[data-loading][data-loading-appearance="solid"] > [data-slot="label"],
.df-btn[data-loading][data-loading-appearance="solid"] > [data-slot="leading"]:not(:has([data-df="spinner"])),
.df-btn[data-loading][data-loading-appearance="solid"] > [data-slot="trailing"]:not(:has([data-df="spinner"])) {
  opacity: var(--opacity-disabled);
}

:where([data-df="button"][aria-invalid="true"]) {
  border-color: var(--destructive);
  box-shadow: var(--focus-ring-error);
}

:where([data-df="button"] svg) {
  pointer-events: none;
  flex-shrink: 0;
  width: calc(4 * var(--spacing-unit, 0.25rem));
  height: calc(4 * var(--spacing-unit, 0.25rem));
}

:where([data-df="button"][data-variant="default"]) {
  background-color: var(--primary);
  color: var(--primary-foreground);
}
:where([data-df="button"][data-variant="default"]:hover) {
  background-color: color-mix(in oklch, var(--primary) 80%, var(--background));
}

:where([data-df="button"][data-variant="outline"]) {
  border-color: var(--border);
  background-color: color-mix(in oklch, var(--input) 30%, var(--background));
}
:where([data-df="button"][data-variant="outline"]:hover) {
  background-color: color-mix(in oklch, var(--input) 50%, var(--background));
  color: var(--foreground);
}
:where([data-df="button"][data-variant="outline"][aria-expanded="true"]) {
  background-color: var(--muted);
  color: var(--foreground);
}

:where([data-df="button"][data-variant="secondary"]) {
  background-color: var(--secondary);
  color: var(--secondary-foreground);
}
:where([data-df="button"][data-variant="secondary"]:hover) {
  background-color: color-mix(in oklch, var(--secondary), var(--foreground) 5%);
}

:where([data-df="button"][data-variant="ghost"]:hover) {
  background-color: var(--muted);
  color: var(--foreground);
}
:where([data-df="button"][data-variant="ghost"][aria-expanded="true"]) {
  background-color: var(--muted);
  color: var(--foreground);
}

:where([data-df="button"][data-variant="plain"]) {
  border-color: transparent;
  background-color: transparent;
  isolation: isolate;
}
:where([data-df="button"][data-variant="plain"][data-size^="icon"]) {
  border-radius: var(--df-button-plain-hover-radius);
  overflow: visible;
}
:where([data-df="button"][data-variant="plain"][data-size^="icon"] svg) {
  filter: var(--df-button-plain-glyph-filter);
