  --df-popover-surface-fg: var(--df-neutral-900);
  --df-popover-border-color: color-mix(
    in oklch,
    var(--df-popover-surface-fg) 12%,
    transparent
  );
  --df-popover-description-color: color-mix(
    in oklch,
    var(--df-popover-surface-fg) 68%,
    transparent
  );
}

:where([data-df="popover-content"][data-size="sm"]) {
  --df-popover-max-width: var(--df-popover-width-sm);
  --df-popover-inset-top: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-right: calc(3 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-bottom: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-left: calc(3 * var(--spacing-unit, 0.25rem));
  --df-popover-gap: calc(2 * var(--spacing-unit, 0.25rem));
  --df-popover-radius: var(--radius-xl);
  font-size: var(--df-text-13);
}

:where([data-df="popover-content"][data-size="md"]) {
  --df-popover-max-width: var(--df-popover-width);
}

:where([data-df="popover-content"][data-size="lg"]) {
  --df-popover-max-width: var(--df-popover-width-lg);
  --df-popover-inset-top: calc(4 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-right: calc(5 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-bottom: calc(4 * var(--spacing-unit, 0.25rem));
  --df-popover-inset-left: calc(5 * var(--spacing-unit, 0.25rem));
  --df-popover-gap: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-popover-radius: var(--radius-2xl);
  font-size: var(--df-text-base);
}

:where([data-df="popover-content"][data-portal="false"]) {
  isolation: isolate;
  z-index: auto;
}

:where([data-df="popover-arrow"]) {
  position: absolute;
  width: var(--df-popover-arrow-size);
  height: var(--df-popover-arrow-size);
  background-color: var(--df-popover-surface);
  transform: rotate(45deg);
  pointer-events: none;
}

:where([data-df="popover-content"][data-side="top"] [data-df="popover-arrow"]) {
  bottom: calc(-1 * var(--df-popover-arrow-offset));
  border-right: var(--df-popover-border-width) solid var(--df-popover-border-color);
  border-bottom: var(--df-popover-border-width) solid var(--df-popover-border-color);
}

:where([data-df="popover-content"][data-side="bottom"] [data-df="popover-arrow"]) {
  top: calc(-1 * var(--df-popover-arrow-offset));
  border-left: var(--df-popover-border-width) solid var(--df-popover-border-color);
  border-top: var(--df-popover-border-width) solid var(--df-popover-border-color);
}

:where([data-df="popover-content"][data-side="left"] [data-df="popover-arrow"]) {
  right: calc(-1 * var(--df-popover-arrow-offset));
  border-right: var(--df-popover-border-width) solid var(--df-popover-border-color);
  border-top: var(--df-popover-border-width) solid var(--df-popover-border-color);
}

:where([data-df="popover-content"][data-side="right"] [data-df="popover-arrow"]) {
  left: calc(-1 * var(--df-popover-arrow-offset));
  border-left: var(--df-popover-border-width) solid var(--df-popover-border-color);
  border-bottom: var(--df-popover-border-width) solid var(--df-popover-border-color);
}

:where([data-df="popover-content"][data-side="top"] [data-df="popover-arrow"]),
:where([data-df="popover-content"][data-side="bottom"] [data-df="popover-arrow"]) {
  left: var(--df-anchor-arrow-cross, 50%);
  margin-left: calc(-1 * var(--df-popover-arrow-align-nudge));
  right: auto;
}

:where([data-df="popover-content"][data-side="left"] [data-df="popover-arrow"]),
:where([data-df="popover-content"][data-side="right"] [data-df="popover-arrow"]) {
  top: var(--df-anchor-arrow-cross, 50%);
  margin-top: calc(-1 * var(--df-popover-arrow-align-nudge));
  bottom: auto;
}

:where([data-df="popover-header"]) {
  display: flex;
  flex-direction: column;
  gap: var(--df-popover-header-gap);
  font-size: inherit;
}

:where([data-df="popover-header-bar"]) {
  display: flex;
  min-width: 0;
  align-items: center;
  justify-content: space-between;
  gap: var(--df-popover-header-bar-gap);
}

:where([data-df="popover-header-bar"] > [data-df="popover-title"]) {
  flex: 1 1 auto;
  min-width: 0;
}

:where(
  [data-df="popover-header-bar"] > [data-df="popover-close"],
  [data-df="popover-header-bar"] > [data-df-popover-close]
) {
  flex-shrink: 0;
}

:where([data-df="popover-title"]) {
  margin: 0;
  color: var(--df-popover-title-color);
  font-family: var(--df-popover-title-font);
  font-size: var(--df-popover-title-size);
  font-weight: var(--df-popover-title-weight);
  letter-spacing: var(--df-popover-title-tracking);
  line-height: var(--df-popover-title-leading);
}

:where([data-df="popover-title"][data-badge]) {
  display: flex;
  min-width: 0;
  gap: calc(2 * var(--spacing-unit, 0.25rem));
}

:where([data-df="popover-title"][data-badge="end"]) {
  flex-direction: row;
  align-items: center;
  justify-content: space-between;
}

:where([data-df="popover-title"][data-badge="below"]) {
  flex-direction: column;
  align-items: flex-start;
}

:where([data-df="popover-title-text"]) {
  min-width: 0;
}

:where([data-df="popover-title-badge"]) {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
}

:where([data-df="popover-description"]) {
  margin: 0;
  color: var(--df-popover-description-color);
  font-family: var(--df-popover-description-font);
  font-size: var(--df-popover-description-size);
  font-weight: var(--df-popover-description-weight);
  letter-spacing: var(--df-popover-description-tracking);
  line-height: var(--df-popover-description-leading);
}

:where([data-df="popover-body"]) {
  display: flex;
  min-width: 0;
  flex: 1 1 auto;
  flex-direction: column;
  gap: calc(2 * var(--spacing-unit, 0.25rem));
}

:where([data-df="popover-footer"]) {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: flex-end;
  gap: var(--df-popover-footer-gap);
  padding: var(--df-popover-footer-padding-top)
    var(--df-popover-footer-padding-x)
    var(--df-popover-footer-padding-bottom);
}

:where([data-df="popover-footer"][data-justify="between"]) {
  justify-content: space-between;
}

:where([data-df="popover-footer"][data-justify="start"]) {
  justify-content: flex-start;
}

:where([data-df="popover-close"]) {
  display: inline-flex;
}

:where([data-df="options-panel-content"]) {
  z-index: var(--z-overlay);
  display: flex;
  width: fit-content;
  max-width: min(
    var(--df-options-panel-max-width),
    calc(100vw - 8 * var(--spacing-unit, 0.25rem))
  );
  flex-direction: column;
  gap: 0;
  overflow: hidden;
  border-radius: var(--radius-2xl);
  background-color: var(--popover);
  padding: 0;
  color: var(--popover-foreground);
  box-shadow: var(--df-shadow-2xl), var(--df-shadow-ring);
  outline: none;
}

:where([data-df="options-panel-content"][data-portal="false"]) {
  isolation: isolate;
  z-index: auto;
}

:where([data-df="options-panel-body"]) {
  max-height: min(60vh, var(--df-options-panel-max-height));
  overflow-y: auto;
}

:where(
  [data-df="options-panel-content"][data-portal="false"] [data-df="options-panel-body"]
) {
  max-height: none;
  overflow-y: visible;
}

:where([data-df="options-panel-footer"]) {
  --df-options-panel-footer-gap-x: calc(2 * var(--spacing-unit, 0.25rem));
  --df-options-panel-footer-gap-y: calc(2.5 * var(--spacing-unit, 0.25rem));
  display: flex;
  flex-direction: column;
  gap: var(--df-options-panel-footer-gap-y);
}

:where([data-df="options-panel-footer-actions"]) {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: var(--df-options-panel-footer-gap-x);
}

:where([data-df="options-panel-footer-meta"]) {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--df-options-panel-footer-gap-x);
  font-size: var(--df-text-xs);
  color: var(--muted-foreground);
}

:where([data-df="options-panel-header"]) {
  display: flex;
  flex-direction: column;
  gap: 0;
}

:where([data-df="options-panel-title"]) {
  font-size: var(--df-text-sm);
  font-weight: var(--df-font-weight-semibold);
  letter-spacing: var(--df-tracking-snug);
}

:where([data-df="option-list"]) {
  position: relative;
  display: inline-flex;
  max-width: 100%;
  min-width: 0;
  flex-direction: column;
  align-items: stretch;
}

:where([data-df="select-trigger"]) {
  --df-select-bg: var(--background);
  --df-select-border: var(--input);
  --df-select-hover-border: var(--foreground);
  --df-select-fg: var(--foreground);
  --df-select-error-border: var(--destructive);
  --df-select-icon-size: calc(4 * var(--spacing-unit, 0.25rem));
  --df-select-line-height: var(--df-leading-5);
  --df-select-optical-shift: var(--df-control-optical-shift);
  --df-select-padding-top: calc(2 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(3 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(2 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(3 * var(--spacing-unit, 0.25rem));
  display: flex;
  width: fit-content;
  max-width: 100%;
  min-width: 0;
  align-items: center;
  justify-content: space-between;
  gap: calc(1.5 * var(--spacing-unit, 0.25rem));
  border-radius: var(--radius-4xl);
  border: var(--border-width-hairline) solid var(--df-select-border);
  background-color: var(--df-select-bg);
  color: var(--df-select-fg);
  padding-top: var(--df-select-padding-top);
  padding-right: var(--df-select-padding-right);
  padding-bottom: var(--df-select-padding-bottom);
  padding-left: var(--df-select-padding-left);
  font-size: var(--df-text-sm);
  line-height: var(--df-select-line-height);
  white-space: nowrap;
  transition: color var(--df-duration-base), border-color var(--df-duration-base),
    box-shadow var(--df-duration-base);
  outline: none;
  cursor: pointer;
}

:where([data-df="select-trigger"][data-variant="secondary"]) {
  --df-select-bg: color-mix(in oklch, var(--secondary) 55%, var(--background));
  --df-select-border: transparent;
  --df-select-fg: var(--secondary-foreground);
}

:where([data-df="select-trigger-icon"]) {
  display: inline-flex;
  flex-shrink: 0;
  align-items: center;
  justify-content: center;
  width: var(--df-select-icon-size);
  height: var(--df-select-icon-size);
  line-height: 0;
  color: currentColor;
  pointer-events: none;
}

:where([data-df="select-trigger-icon"] svg) {
  display: block;
  width: 100%;
  height: 100%;
}

:where([data-df="select-trigger-chevron"]) {
  flex-shrink: 0;
  width: var(--df-select-icon-size);
  height: var(--df-select-icon-size);
  color: var(--muted-foreground);
  pointer-events: none;
}

/* Bottom margin raises the rounded text baseline onto the trigger midline. */
:where([data-df="select-value"]) {
  flex: 1 1 auto;
  min-width: 0;
  overflow: hidden;
  margin-bottom: calc(2 * var(--df-select-optical-shift));
  text-align: left;
  text-overflow: ellipsis;
  white-space: nowrap;
}

:where([data-df="select-value"][data-layout="stacked"]) {
  overflow: hidden;
  margin-bottom: 0;
  text-overflow: clip;
  white-space: normal;
}

:where([data-df="select-value-stack"]) {
  display: flex;
  min-width: 0;
  flex-direction: column;
  align-items: flex-start;
  gap: calc(0.5 * var(--spacing-unit, 0.25rem));
}

:where([data-df="select-value-title"]) {
  min-width: 0;
  max-width: 100%;
  overflow: hidden;
  font-weight: var(--df-font-weight-medium);
  line-height: var(--df-select-line-height, var(--df-leading-5));
  text-overflow: ellipsis;
  white-space: nowrap;
}

:where([data-df="select-value-secondary"]) {
  min-width: 0;
  max-width: 100%;
  overflow: hidden;
  color: var(--muted-foreground);
  font-size: var(--df-text-xs);
  font-weight: var(--df-font-weight-normal);
  line-height: var(--df-leading-4);
  text-overflow: ellipsis;
  white-space: nowrap;
}

:where([data-df="select-trigger"][data-placeholder] [data-df="select-value"]),
:where([data-df="select-value"][data-empty]) {
  color: var(--muted-foreground);
  font-weight: var(--df-font-weight-normal);
}

:where([data-df="select-trigger"][data-size="sm"]) {
  --df-select-icon-size: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-top: calc(1.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(1.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(2.5 * var(--spacing-unit, 0.25rem));
  height: var(--df-control-height-sm);
  gap: calc(1 * var(--spacing-unit, 0.25rem));
  font-size: var(--df-text-13);
}

:where([data-df="select-trigger"][data-size="md"]),
:where([data-df="select-trigger"][data-size="default"]) {
  height: var(--df-control-height-md);
  font-size: var(--df-text-sm);
}

:where([data-df="select-trigger"][data-size="lg"]) {
  --df-select-icon-size: calc(4.5 * var(--spacing-unit, 0.25rem));
  --df-select-line-height: var(--df-leading-6);
  --df-select-padding-top: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(3.5 * var(--spacing-unit, 0.25rem));
  height: var(--df-control-height-lg);
  gap: calc(2 * var(--spacing-unit, 0.25rem));
  font-size: var(--df-text-base);
}

:where([data-df="select-trigger"][data-selection-mode="multiple"]) {
  height: auto;
  min-height: var(--df-control-height-md);
  white-space: normal;
}

:where([data-df="select-trigger"][data-selection-mode="multiple"][data-size="sm"]) {
  min-height: var(--df-control-height-sm);
}

:where([data-df="select-trigger"][data-selection-mode="multiple"][data-size="lg"]) {
  min-height: var(--df-control-height-lg);
}

:where([data-df="select-field"]) {
  --df-select-overlap-inset: calc(3 * var(--spacing-unit, 0.25rem));
  --df-select-overlap-label-pad: calc(1 * var(--spacing-unit, 0.25rem));
  --df-select-overlap-label-size: var(--df-text-11);
  --df-select-overlap-label-bg: var(--background);
  --df-select-inset-label-size: var(--df-text-11);
  --df-select-inset-gap: calc(0.5 * var(--spacing-unit, 0.25rem));
  display: flex;
  width: fit-content;
  max-width: 100%;
  min-width: 0;
  flex-direction: column;
  align-items: stretch;
  gap: calc(1.5 * var(--spacing-unit, 0.25rem));
}

:where([data-df="select-field"][data-label-position="overlap"]) {
  padding-top: calc(var(--df-select-overlap-label-size) * 0.5);
}

:where([data-df="select-field"][data-disabled]) {
  cursor: not-allowed;
}

:where([data-df="select-field"] [data-df="label"]) {
  color: var(--df-select-label, var(--foreground));
}

:where([data-df="select-field"][data-invalid-label] [data-df="label"]) {
  color: var(--df-select-error-label, var(--destructive));
}

:where([data-df="select-field"][data-disabled] [data-df="label"]),
:where([data-df="select-field"][data-disabled] [data-df="label-subtext"]),
:where([data-df="select-field"][data-disabled] [data-df="select-field-aside-subtext"]),
:where([data-df="select-field"][data-disabled] [data-df="select-field-hint"]),
:where([data-df="select-field"][data-disabled] [data-df="select-overlap-label"]),
:where([data-df="select-field"][data-disabled] [data-df="select-inset-label"]) {
  color: var(--df-field-disabled-fg);
}

:where([data-df="select-field"] [data-df="select-trigger"]) {
  width: 100%;
}

:where([data-df="select-overlap"]) {
  position: relative;
  display: flex;
  width: 100%;
  min-width: 0;
  flex-direction: column;
  align-items: stretch;
  overflow: visible;
}

:where([data-df="select-overlap-label"]) {
  position: absolute;
  top: 0;
  left: var(--df-select-overlap-inset);
  z-index: var(--z-raised);
  display: inline-flex;
  max-width: calc(100% - (2 * var(--df-select-overlap-inset)));
  align-items: center;
  gap: calc(1 * var(--spacing-unit, 0.25rem));
  padding-inline: var(--df-select-overlap-label-pad);
  overflow: hidden;
  border-radius: var(--radius-sm);
  background-color: var(--df-select-overlap-label-bg);
  color: var(--df-select-label, var(--muted-foreground));
  font-size: var(--df-select-overlap-label-size);
  font-weight: var(--df-font-weight-medium);
  line-height: var(--df-leading-none);
  white-space: nowrap;
  transform: translateY(-50%);
}

:where([data-df="select-field"][data-invalid-label] [data-df="select-overlap-label"]) {
  color: var(--df-select-error-label, var(--destructive));
}

:where([data-df="select-overlap-label"] [data-df="label"]) {
  display: inline-flex;
  max-width: 100%;
  min-width: 0;
  flex: 1 1 auto;
  flex-direction: row;
  align-items: center;
  gap: 0;
  overflow: hidden;
  color: inherit;
  font-size: inherit;
  font-weight: inherit;
  line-height: inherit;
}

:where([data-df="select-overlap-label"] [data-df="label-row"]),
:where([data-df="select-overlap-label"] [data-df="label-title"]),
:where([data-df="select-overlap-label"] [data-df="label-text"]) {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

:where([data-df="select-field-aside-subtext"]) {
  margin: 0;
  color: var(--muted-foreground);
  font-size: var(--df-text-13);
  font-weight: var(--df-font-weight-normal);
  line-height: var(--df-leading-5);
}

:where([data-df="select-trigger"][data-label-position="inset"]) {
  --df-select-padding-top: calc(3 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(3 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(3.5 * var(--spacing-unit, 0.25rem));
  height: auto;
  min-height: var(--df-control-height-xl);
  align-items: center;
  white-space: normal;
}

:where([data-df="select-trigger"][data-label-position="inset"][data-size="sm"]) {
  --df-select-padding-top: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(3 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(2.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(3 * var(--spacing-unit, 0.25rem));
  min-height: var(--df-control-height-lg);
}

:where([data-df="select-trigger"][data-label-position="inset"][data-size="lg"]) {
  --df-select-padding-top: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-right: calc(4 * var(--spacing-unit, 0.25rem));
  --df-select-padding-bottom: calc(3.5 * var(--spacing-unit, 0.25rem));
  --df-select-padding-left: calc(4 * var(--spacing-unit, 0.25rem));
  min-height: var(--df-control-height-2xl);
}

:where([data-df="select-trigger"][data-value-layout="stacked"]) {
  --df-title-line: var(--df-select-line-height);
  --df-leading-size: var(--df-select-icon-size);
  --df-title-lead-offset: calc(
    (var(--df-title-line) - var(--df-leading-size)) / 2
  );
  align-items: flex-start;
  height: auto;
  white-space: normal;
}

:where([data-df="select-trigger"][data-value-layout="stacked"]:not([data-label-position="inset"])) {
  min-height: var(--df-control-height-md);
}

:where([data-df="select-trigger"][data-value-layout="stacked"]:not([data-label-position="inset"])[data-size="sm"]) {
  min-height: var(--df-control-height-sm);
}

:where([data-df="select-trigger"][data-value-layout="stacked"]:not([data-label-position="inset"])[data-size="lg"]) {
  min-height: var(--df-control-height-lg);
}

:where([data-df="select-trigger"][data-value-layout="stacked"] [data-df="select-trigger-icon"]) {
  margin-top: var(--df-title-lead-offset);
}

:where([data-df="select-trigger"][data-value-layout="stacked"] [data-df="select-trigger-chevron"]) {
  align-self: center;
}

:where([data-df="select-trigger-stack"]) {
  display: flex;
  flex: 1 1 auto;
  min-width: 0;
  flex-direction: column;
  align-items: stretch;
  justify-content: center;
  gap: var(--df-select-inset-gap);
}

:where([data-df="select-inset-label"]) {
  display: inline-flex;
  max-width: 100%;
